using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Diagnostics;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Breaking change: Cosmos provider no longer supports synchronous I/O.
        // Suppress only if async migration is not yet complete.
        optionsBuilder.ConfigureWarnings(w => w.Ignore(CosmosEventId.SyncNotSupported));
    }
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change: discriminator property renamed "$type"; keep old name for existing docs
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change: id no longer contains discriminator (was "Blog|1", now "1")
            entity.HasDiscriminatorInJsonId();

            // Breaking change: key property now maps directly to JSON "id"; restore shadow id
            // so existing docs that store the key separately are still readable
            entity.HasShadowId();
        });
        // Removed HasIndex – Cosmos indexes all properties by default; HasIndex now throws.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

